import numpy as np
from openai import OpenAI

client = OpenAI()

def embed(text: str) -> np.ndarray:
    resp = client.embeddings.create(model="text-embedding-3-small", input=text)
    return np.array(resp.data[0].embedding)

def cosine(a: np.ndarray, b: np.ndarray) -> float:
    return float(a @ b / (np.linalg.norm(a) * np.linalg.norm(b)))

q = embed("How do I reset my password?")
doc1 = embed("Steps to recover account access and set a new password")
doc2 = embed("Our refund policy for annual subscriptions")

print(cosine(q, doc1))  # ~0.6-0.8 (similar meaning)
print(cosine(q, doc2))  # much lower (unrelated)
